List / Dictionary Comprehension**PythonВЮё вЇћ PythonВіцвЪйЖ▓ї ВъЉВё▒ьЋўЖИ░ВюёьЋ┤Вёю ВЮ┤ ComprehensionВЮё ВЮ┤ьЋ┤ьЋўЖ│а ВаЂВаѕьъѕ Въў ВѓгВџЕьЋ┤ВЋ╝ьЋювІц. List Comprehension вдгВіцьіИВЮў Ж░Ђ ВџћВєїВЌљ 2вЦ╝ Ж│▒ьЋ┤Вёю ВЃѕвАюВџ┤ вдгВіцьіИ ВЃЮВё▒ьЋўЖИ░ (for-loop + list comprehension) numbers = [1, 2, 3, 4, 5] new_numbers = [] for i in numbers: new_numbers.append(i*2) print(new_numbers) # list comprehensionВЮё ВѓгВџЕьЋ┤Вёю ВЋёвъўВЎђ Ж░ЎВЮ┤ Ж░ёвІеьЋўЖ▓ї ВъЉВё▒ВЮё ьЋ┤Вцё Вѕў ВъѕвІц. new_numbers = [i*2 for i in numbers] вдгВіцьіИВЮў ВџћВєїВцЉВЌљ ВДЮВѕўВЮИ ВѕўвЦ╝ Вёав│ёьЋ┤Вёю ьЋ┤вІ╣ ВѕўВЌљ ВаюЖ│▒ВЮё ьЋ┤Вёю ВЃѕвАюВџ┤ вдгВіцьіИ ВЃЮВё▒ьЋўЖИ░ (for-loop + list comprehension) numbers = [1, 2, 3, 4, 5] new_numbers = [] # numbers ВъљвБї ВцЉ ВДЮВѕўВЮ╝вЋївДї ВаюЖ│▒ьЋўВЌг new_numbersВЌљ ВХћЖ░ђьЋювІц. for i in numbers: if i % 2 == 0: new_numbers.append(i**2) # ВА░Ж▒┤вгИВЮ┤ ьЋўвѓўВЮ╝вЋїВЌљвіћ forвгИ вњцВЌљ ВюёВ╣ўьЋўвЈёвАЮ ьЋювІц. new_numbers = [i**2 for i in numbers if i % 2 == 0] вдгВіцьіИВЮў ВџћВєїВцЉВЌљ ВДЮВѕўвіћ ВаюЖ│▒ВЮё, ьЎђВѕўВЮИ Ж▓йВџ░ВЌљвіћ ВёИВаюЖ│▒ВЮё ьЋ┤Вёю ВЃѕвАюВџ┤ вдгВіцьіИвЦ╝ ВЃЮВё▒ьЋўЖИ░ (list comprehension + Ternary operator) numbers = [1, 2, 3, 4, 5] new_numbers = [] # numbers ВъљвБї ВцЉ ВДЮВѕўВЮ╝вЋївДї ВаюЖ│▒ьЋўВЌг new_numbersВЌљ ВХћЖ░ђьЋювІц. # ЖиИваЄВДђ ВЋіВЮё Ж▓йВџ░, ВёИВаюЖ│▒ьЋўВЌг new_numbersВЌљ ВХћЖ░ђьЋювІц. # expressionвѓ┤ВЌљ ВА░Ж▒┤ВЮё вІгВЋёВцёвЋїВЌљвіћ Вѓ╝ьЋГВЌ░Вѓ░ВъљвАю ВА░Ж▒┤В▓ўвдгвЦ╝ ьЋ┤ВцђвІц. new_numbers = [item**2 if item % 2 == 0 else item**3 for item in numbers] FizzBuzz (for-loop &amp; if-statement) # Fizzbuzz # 3ВЮў в░░Вѕў : Fizz, 5ВЮў в░░Вѕў : Buzz, 15ВЮў в░░Вѕў FizzBuzz numbers = [i for i in range(1, 100+1)] fizzbuzz_list = [] for i in numbers: if i % 15 == 0: fizzbuzz_list.append(&#39;FizzBuzz&#39;) elif i % 3 == 0: fizzbuzz_list.append(&#39;Fizz&#39;) elif i % 5 == 0: fizzbuzz_list.append(&#39;Buzz&#39;) else: fizzbuzz_list.append(i) # list comprehensionВю╝вАю convert FizzBuzz (list comprehension + Ternary operator) # fizzbuzz with list comprehension numbers = [i for i in range(1, 100+1)] fizzbuzz_list = [&#39;fizzbuzz&#39; if i%15==0 else \ &#39;fizz&#39; if i%3==0 else \ &#39;buzz&#39; if i%5==0 else \ i for i in numbers] Leap year(list comprehension + for-loop, if-statement) # Leap year # Constraint: 1999~2101 year_list = [i for i in range(1999, 2101+1)] # 100Вю╝вАю вѓўвѕаВДђвЕ┤ leap yearЖ░ђ ВЋёвІѕвІц. # 4вАю вѓўвѕаВДђЖ│а, (100Вю╝вАю вѓўвѕаВДђВДђ ВЋіЖ▒░вѓў, 400Вю╝вАю вѓўвѕаВДђвіћ Ж▓йВџ░) is_leap_list = [] # 2000 = leap_year # 2100 = plain_year year = 2000 for year in year_list: if year%4==0 and (year%100!=0 or year%400==0): is_leap_list.append(&#39;leap_year&#39;) else: is_leap_list.append(year) Leap year(list comprehension with Ternary operator) # Leap year with list comprehension # Leap year: 4ВЮў в░░ВѕўВЮ┤вЕ┤Вёю, 100ВЮў в░░ВѕўЖ░ђ ВЋёвІѕЖ▒░вѓў 400ВЮў в░░ВѕўВЮИ ВЌ░вЈё # Constraint: 1999~2101 # Output: &#39;leap_year&#39; if i is leap_year else, i years = [i for i in range(1999, 2101+1)] is_leap_list = [&#39;leap_year&#39; if year%4==0 and (year%100!=0 or year%400==0) else year for year in years] # 2000 = leap_year # 2100 = plain_year print(is_leap_list) Functionalize the process of filtering leap year def is_leap(year): if year%4==0 and (year%100!=0 or year%400==0): return True return False is_leap_list = [&#39;leap_year&#39; if isi_leap(year) else year for year in years] print(is_leap_list) Dictionary Comprehensionfruits = &#123;&#39;a&#39;:&#39;apple&#39;, &#39;b&#39;:&#39;banana&#39;, &#39;c&#39;:&#39;coconut&#39;, &#39;d&#39;:&#39;durian&#39;&#125; over_six_fruits = &#123;&#125; # fruite value ВцЉВЌљ вгИВъљВЌ┤ ЖИИВЮ┤Ж░ђ 6в│┤вІц ьЂ░ Ж▓йВџ░ВЌљ ВЃѕвАюВџ┤ dictВЌљ вІ┤ВЋёВёю ВЃѕвАюВџ┤ dict в│ђВѕўвЦ╝ ВЃЮВё▒ for k, v in fruits.items(): if len(v) &gt; 6: over_six_fruits[k] = v ВюёВЮў ВйћвЊювЦ╝ Dictionary comprehensionВю╝вАю ВъЉВё▒ # Dictionary comprehension over_six_fruits = &#123;k:v for k,v in fruits.items() if len(v) &gt; 6&#125; Dictionary + for-loop with if-statement number_dict = &#123;&#39;pi&#39;:3.1415, &#39;e&#39;:2.71828, &#39;year&#39;:2021, &#39;month&#39;:2, &#39;day&#39;:1&#125; new_number_dict = &#123;&#125; for k,v in number_dict.items(): if v &lt; 3: new_number_dict[k] = v ** 2 print(new_number_dict) ВюёВЮў ВйћвЊювЦ╝ Dictionary comprehensionВю╝вАю ВъЉВё▒ number_dict = &#123;&#39;pi&#39;:3.1415, &#39;e&#39;:2.71828, &#39;year&#39;:2021, &#39;month&#39;:2, &#39;day&#39;:1&#125; # ВЋёвъўВЎђ Ж░ЎВЮ┤ Вѓ╝ьЋГВЌ░Вѓ░ВъљвЦ╝ ВЮ┤ВџЕьЋ┤Вёю ВА░Ж▒┤В▓ўвдгвЦ╝ ьЋ┤Вёю ВъЉВё▒ВЮё ьЋ┤ Вцё Вѕў ВъѕвІц. # ВЋъВЌљВёю keyвЦ╝ ВЮ┤в»И ВаЋВЮўьЋ┤ВБ╝ВЌѕЖИ░ вЋївгИВЌљ elseЖхгвгИВЌљВёювіћ keyВЌљ вїђьЋю ВаЋВЮўвЦ╝ ВЃЮвъхьЋўЖ│а valueВЌљ вїђьЋю ВёаВќИвДї вёБВќ┤ВцђвІц. new_number_dict = &#123;k:v**2 if v &lt; 3 else v-1 for k,v in number_dict.items()&#125; вдгВіцьіИВЮў Ж░Ђ вгИВъљВЌ┤ ВџћВєїВЮў ЖИИВЮ┤вЦ╝ ЖхгьЋ┤Вёю ВЃѕвАюВџ┤ вдгВіцьіИ в│ђВѕў ВЃЮВё▒ (list comprehension + for-loop with map) a_word_list = [&#39;aback&#39;,&#39;abacus&#39;,&#39;abandon&#39;,&#39;abandoned&#39;,&#39;abandonment&#39;,&#39;abashed&#39;,&#39;abate&#39;,&#39;abbey&#39;,] ВІцьќЅвљўвіћ ВѕюЖ░ёВЌљ вѓўВўцвіћ Ж▓Ѓ a_word_len_list = [len(s) for s in a_word_list] # dict.get() # dict.setdefault() a_word_len_list = [] for len_ in map(len, a_word_list): a_word_len_list.append(len_) dict.get([key], [default value])ВЎђ dict.setdefault([key], [default value]) ьЎюВџЕ # len_dict = &#123;&#125; # ьўёВъг len_dictВЌљ len(apple)вЦ╝ keyЖ░њВю╝вАю Ж░ђВДђвіћ Ж░њВЮ┤ ВЌєВю╝вЕ┤ ьЋ┤вІ╣ keyВЌљ ьЋ┤вІ╣ьЋўвіћ в│ђВѕўвЦ╝ 0Вю╝вАю В┤ѕЖИ░ьЎћьЋ┤Вёю вёБВќ┤ВБ╝Ж│а, 1ВЮё вѕёВаЂьЋ┤Вёю вЇћьЋ┤ВцђвІц. # ьўёВъг leln_dictВЌљ len(apple) 5вЮ╝віћ ьѓцЖ░ђ ВъѕвІцвЕ┤ ЖИ░ВА┤ Ж░њВЌљ 1ВЮё вЇћьЋ┤Вёю вѕёВаЂьЋ┤ВцђвІц. len_dict[len(&#39;apple&#39;)] = len_dict.get(len(&#39;apple&#39;), 0) + 1 # keyвАю len(&#39;amp&#39;)ВЮў Ж░њВЮИ 3Вю╝вАю ВА░ьџївЦ╝ ьќѕВЮёвЋї Ж░њВЮ┤ ВЌєВю╝вЕ┤ defaultвАю 0ВЮё ВёаВќИьЋ┤ВБ╝Ж│а, В┤ѕЖИ░Ж░њВЌљ 1ВЮё вѕёВаЂьЋ┤Вёю вЇћьЋ┤ВцђвІц. # ВА┤ВъгьЋювІцвЕ┤ ЖИ░ВА┤ Ж░њВЌљ 1ВЮё вЇћьЋ┤Вёю вѕёВаЂВЮё ьЋ┤ВцђвІц. len_dict[len(&#39;amp&#39;)] = len_dict.get(len(&#39;amp&#39;), 0) + 1 # ВѕЎВаю) ВюёВЮў ВйћвЊювЦ╝ dictionary comprehension Вю╝вАю в░ћЖ┐ћв│┤ЖИ░. len_dict = &#123;&#125; for word in a_word_list: len_dict[len(word)] = len_dict.get(len(word), 0) + 1 print(len_dict) &quot;&quot;&quot; sample output: &#123; 5: [&#39;apple&#39;, &#39;among&#39;] &#125; &quot;&quot;&quot; filtered_dict = &#123;&#125; filtered_dict.setdefault(len(&#39;among&#39;), []).append(&#39;among&#39;) filtered_dict.setdefault(len(&#39;among&#39;), []).append(&#39;among&#39;) filtered_dict.setdefault(len(&#39;among&#39;), []).append(&#39;amp&#39;) # вІеВќ┤ВЮў ЖИИВЮ┤вЦ╝ ЖИ░ВцђВю╝вАю вІеВќ┤вЊцВЮё вХёвЦў for word in a_word_list: filtered_dict.setdefault(len(word), []).append(word) # В▓Фв▓ѕВДИ ВЋїьїїв▓│ ЖИ░ВцђВю╝вАю вІеВќ┤вЊцВЮё вХёвЦў for word in a_word_list: filtered_dict.setdefault(word[0], []).append(word) print(filtered_dict) File I/O ьїїВЮ╝ВЮё ВЌ┤Ж│а(open), ВЊ░Ж│а(write), ВЮйЖИ░(readline) ВІцВіх # numbers.txt ьїїВЮ╝ ВЌ┤Ж│а ВЊ░ЖИ░ ВёцВаЋ в░Ј вгИВъљВЌ┤ encoding в░ЕВІЮВЮё &#39;utf-8&#39;Вю╝вАю ВёцВаЋ f = open(&#39;./numbers.txt&#39;, &#39;w&#39;, encoding=&#39;utf-8&#39;) # ьїїВЮ╝ВЌљ hello ВЊ░ЖИ░ f.write(&#39;hello&#39;) # file Ж░ЮВ▓┤ВЮў life-cycle ВбЁвБї f.close() # numbers.txt ьїїВЮ╝ ВЌ┤Ж│а ВЮйЖИ░ ВёцВаЋ в░Ј вгИВъљВЌ┤ encoding в░ЕВІЮВЮё &#39;utf-8&#39;Вю╝вАю ВёцВаЋ f = open(&#39;./numbers.txt&#39;, &#39;r&#39;, encoding=&#39;utf-8&#39;) # ьїїВЮ╝ВЮў ьЋю ВцёВЮё ВЮйЖ│а(readline) text в│ђВѕўВЌљ вІ┤ЖИ░ text = f.readline() # ьїїВЮ╝вАювХђьё░ ВЮйВЮђ text в│ђВѕўвЦ╝ ВХюваЦ print(text) # file Ж░ЮВ▓┤ВЮў life-cycle ВбЁвБї f.close() ВюёВЌљВёювіћ openВю╝вАю ьїїВЮ╝ВЮё ВЌ░ ьЏёВЌљ ЖиИ вѓ┤ВџЕВЮё ьЉюВІюьЋўЖ│а closeьЋўВўђвІц. ВЋёвъў ВйћвЊювіћ withВЮё ьЎюВџЕьЋю ВйћвЊю ВъЉВё▒Вю╝вАю, в░ћвАю ВўєВЌљ ВѕўьќЅ ьЋа ьЋеВѕўвЦ╝ вфЁВІюьЋўЖ│а aliasвАю fвЦ╝ ьЋ┤ВБ╝ВЌѕвІц.with ЖхгвгИВЮё ВѓгВџЕьЋўвЕ┤ вфЁВІюВаЂ ьЂ┤вАюВдѕ В▓ўвдгЖ░ђ вХѕьЋёВџћьЋўЖ▓ї вљўв»ђвАю closeвЦ╝ ВЋѕьЋўвіћ ВІцВѕўвЦ╝ ВѓгВаёВЌљ в░ЕВДђьЋа Вѕў ВъѕвІц. with open(&#39;./numbers.txt&#39;, &#39;w&#39;, encoding=&#39;utf-8&#39;) as f: for _ in range(10): f.write(&#39;hello&#39;) with open(&#39;./numbers.txt&#39;, &#39;r&#39;, encoding=&#39;utf-8&#39;) as f: # в│хВѕўВЮў ВцёВЮё ВЮйВЮёвЋїВЌљвіћ .readlines() text_list = f.readlines() # ьЋю ВцёВЮё ВЮйВЮёвЋїВЌљвіћ .readline() for line in text_list: print(line.replace(&#39;
&#39;,&#39;&#39;)) # append modeВЮў ВѓгВџЕ # append modeвЦ╝ ВѓгВџЕьЋўвіћ Ж▓йВџ░, ВЮ┤Ваё вЇ░ВЮ┤ьё░ВЮў EOF(End Of File)вХђьё░ ВЮ┤Вќ┤Вёю ВХћЖ░ђ вЇ░ВЮ┤ьё░Ж░ђ вХЎЖИ░ вЋївгИВЌљ вЇ░ВЮ┤ьё░вЦ╝ ВъЁваЦьЋавЋї enterвЦ╝ В│љВёю Ж░юьќЅ(
) В▓ўвдгвЦ╝ ьЋўЖ│авѓўВёю ЖиИ вІцВЮї appendьЋа вЇ░ВЮ┤ьё░ВЌљ вїђьЋ┤Вёю append modeвЦ╝ ВІцьќЅьЋ┤ВцўВЋ╝ ьЋювІц. # ВЮ┤ВаёВЌљ ВѓйВъЁвљю вЇ░ВЮ┤ьё░ вЂЮВЌљ 
 Ж░ђ ВЌєвіћ Ж▓йВџ░, вІцВЮї append modeвАю ВХћЖ░ђвљўвіћ вЇ░ВЮ┤ьё░віћ ВЮ┤ВаёВЌљ ВѓйВъЁвљю вЇ░ВЮ┤ьё░ВЮў вЂЮВЌљ вХЎвіћвІц. numbers = [i for i in range(1,10+1)] with open(&#39;./numbers.txt&#39;, &#39;a&#39;, encoding=&#39;utf-8&#39;) as f: for i in numbers: # file Ж░ЮВ▓┤вЦ╝ ВѓгВџЕьЋ┤Вёю вЇ░ВЮ┤ьё░вЦ╝ ВЊИвЋїВЌљвіћ в░ўвЊюВІю str ьЃђВъЁВю╝вАю ВъЁваЦВЮё ьЋ┤ВБ╝Вќ┤ВЋ╝ ьЋювІц. f.write(&#39;&#123;&#125;
&#39;.foramt(i)) with open(&#39;./numbers.txt&#39;, &#39;w&#39;, encoding=&#39;utf-8&#39;) as f: print(f.readlines()) CSV module : CSV File Reading and Writing Python documentation : CSV module reference. import csv with open(&#39;customers.csv&#39;, newline=&#39;&#39;) as customer_csv: customers = csv.reader(customer_csv) for row in customers: print(row) &quot;&quot;&quot; [&#39;CustomerID&#39;, &#39;CustomerName&#39;, &#39;ContactName&#39;, &#39;Address&#39;, &#39;City&#39;, &#39;PostalCode&#39;, &#39;Country&#39;] [&#39;1&#39;, &#39;Alfreds Futterkiste&#39;, &#39;Maria Anders&#39;, &#39;Obere Str. 57&#39;, &#39;Berlin&#39;, &#39;12209&#39;, &#39;Germany&#39;] [&#39;2&#39;, &#39;Ana Trujillo Emparedados y helados&#39;, &#39;Ana Trujillo&#39;, &#39;Avda. de la Constituci├│n 2222&#39;, &#39;M├Еxico D.F.&#39;, &#39;05021&#39;, &#39;Mexico&#39;] [&#39;3&#39;, &#39;Antonio Moreno Taquer├Гa&#39;, &#39;Antonio Moreno&#39;, &#39;Mataderos 2312&#39;, &#39;M├Еxico D.F.&#39;, &#39;05023&#39;, &#39;Mexico&#39;] [&#39;4&#39;, &#39;Around the Horn&#39;, &#39;Thomas Hardy&#39;, &#39;120 Hanover Sq.&#39;, &#39;London&#39;, &#39;WA1 1DP&#39;, &#39;UK&#39;] [&#39;5&#39;, &#39;Berglunds snabbk├Хp&#39;, &#39;Christina Berglund&#39;, &#39;Berguvsv├цgen 8&#39;, &#39;Lule├Ц&#39;, &#39;S-958 22&#39;, &#39;Sweden&#39;] ........ &quot;&quot;&quot; JSON (dump, load ВБ╝вАю ВѓгВџЕ) Python documentation : json module reference. import json data = &#123;&#39;users&#39;: [ &#123;&#39;name&#39;: &#39;KD Hong&#39;, &#39;locale&#39;: &#39;Seoul, KR&#39;&#125;, &#123;&#39;name&#39;: &#39;John Doe&#39;, &#39;locale&#39;: &#39;New York, US&#39;&#125;, &#123;&#39;name&#39;: &#39;Jane Doe&#39;, &#39;locale&#39;: &#39;London, UK&#39;&#125; ]&#125; with open(&#39;users.json&#39;, &#39;w&#39;, encoding=&#39;utf-8&#39;) as f: json.dump(data, f) with open(&#39;users.json&#39;, &#39;r&#39;, encoding=&#39;utf-8&#39;) as f: # deserialize des_data = json.load(f) print(des_data) &quot;&quot;&quot; &#123;&#39;users&#39;: [&#123;&#39;name&#39;: &#39;KD Hong&#39;, &#39;locale&#39;: &#39;Seoul, KR&#39;&#125;, &#123;&#39;name&#39;: &#39;John Doe&#39;, &#39;locale&#39;: &#39;New York, US&#39;&#125;, &#123;&#39;name&#39;: &#39;Jane Doe&#39;, &#39;locale&#39;: &#39;London, UK&#39;&#125;]&#125; &quot;&quot;&quot; for row in des_data[&#39;users&#39;]: print(&#39;&#123;&#125; is from &#123;&#125;&#39;.format(row[&#39;name&#39;], row[&#39;locale&#39;])) &quot;&quot;&quot; KD Hong is from Seoul, KR John Doe is from New York, US Jane Doe is from London, UK &quot;&quot;&quot;
